struct EnvelopeBuilder {
  typedef Envelope Table;
  flatbuffers::FlatBufferBuilder &fbb_;
  flatbuffers::uoffset_t start_;
  void add_seq(uint32_t seq) {
    fbb_.AddElement<uint32_t>(Envelope::VT_SEQ, seq, 0);
  }
  void add_ack(uint32_t ack) {
    fbb_.AddElement<uint32_t>(Envelope::VT_ACK, ack, 0);
  }
  void add_ack_bits(uint32_t ack_bits) {
    fbb_.AddElement<uint32_t>(Envelope::VT_ACK_BITS, ack_bits, 0);
  }
  void add_payload_type(wildpaw::protocol::MessagePayload payload_type) {
    fbb_.AddElement<uint8_t>(Envelope::VT_PAYLOAD_TYPE, static_cast<uint8_t>(payload_type), 0);
  }
  void add_payload(flatbuffers::Offset<void> payload) {
    fbb_.AddOffset(Envelope::VT_PAYLOAD, payload);
  }
  explicit EnvelopeBuilder(flatbuffers::FlatBufferBuilder &_fbb)
        : fbb_(_fbb) {
    start_ = fbb_.StartTable();
  }
  flatbuffers::Offset<Envelope> Finish() {
    const auto end = fbb_.EndTable(start_);
    auto o = flatbuffers::Offset<Envelope>(end);
    return o;
  }
};

inline flatbuffers::Offset<Envelope> CreateEnvelope(
    flatbuffers::FlatBufferBuilder &_fbb,
    uint32_t seq = 0,
    uint32_t ack = 0,
    uint32_t ack_bits = 0,
    wildpaw::protocol::MessagePayload payload_type = wildpaw::protocol::MessagePayload::NONE,
    flatbuffers::Offset<void> payload = 0) {
  EnvelopeBuilder builder_(_fbb);
  builder_.add_payload(payload);
  builder_.add_ack_bits(ack_bits);
  builder_.add_ack(ack);
  builder_.add_seq(seq);
  builder_.add_payload_type(payload_type);
  return builder_.Finish();
}

inline bool VerifyMessagePayload(flatbuffers::Verifier &verifier, const void *obj, MessagePayload type) {
  switch (type) {
    case MessagePayload::NONE: {
      return true;
    }
    case MessagePayload::HelloPayload: {
      auto ptr = reinterpret_cast<const wildpaw::protocol::HelloPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::InputPayload: {
      auto ptr = reinterpret_cast<const wildpaw::protocol::InputPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::ActionCommandPayload: {
      auto ptr = reinterpret_cast<const wildpaw::protocol::ActionCommandPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::PingPayload: {
      auto ptr = reinterpret_cast<const wildpaw::protocol::PingPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::WelcomePayload: {
      auto ptr = reinterpret_cast<const wildpaw::protocol::WelcomePayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::SnapshotPayload: {
      auto ptr = reinterpret_cast<const wildpaw::protocol::SnapshotPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::CombatEventPayload: {
      auto ptr = reinterpret_cast<const wildpaw::protocol::CombatEventPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::ProjectileEventPayload: {
      auto ptr = reinterpret_cast<const wildpaw::protocol::ProjectileEventPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    case MessagePayload::EventPayload: {
      auto ptr = reinterpret_cast<const wildpaw::protocol::EventPayload *>(obj);
      return verifier.VerifyTable(ptr);
    }
    default: return true;
  }
}

inline bool VerifyMessagePayloadVector(flatbuffers::Verifier &verifier, const flatbuffers::Vector<flatbuffers::Offset<void>> *values, const flatbuffers::Vector<MessagePayload> *types) {
  if (!values || !types) return !values && !types;
  if (values->size() != types->size()) return false;
  for (flatbuffers::uoffset_t i = 0; i < values->size(); ++i) {
    if (!VerifyMessagePayload(
        verifier,  values->Get(i), types->GetEnum<MessagePayload>(i))) {
      return false;
    }
  }
  return true;
}

